import React from 'react';
import Login from "./components/Login";
import './App.css';
import Register from "./components/Register"

import { BrowserRouter as Router, Route, Routes, Link } from 'react-router-dom';
import DeleteAccount from "./components/DeleteAccount";
import UpdateProfile  from "./components/UpdateProfile";
import {useNavigate} from "react-router-dom";
import VideoBackground from "./components/VideoBackground";

// O componentă mică pentru Logout, ca să putem folosi 'useNavigate'
const LogoutButton: React.FC<{ onLogout: () => void }> = ({ onLogout }) => {
    const navigate = useNavigate();

    const handleClick = () => {
        onLogout(); // Șterge starea din App.tsx
        navigate('/login'); // Redirecționează la login
    };

    return (
        <button onClick={handleClick} className="nav-button logout-button">
            Logout
        </button>
    );
};

const ProfilePage: React.FC = () => {
    return (
        <div>
            <h1>Profilul Meu</h1>
            <UpdateProfile />
            <hr />
            <DeleteAccount />
        </div>

    );
};
const App: React.FC = () => {
    return (
        <Router>
            <div>
                <VideoBackground />
                {/* 3. Actualizează structura barei de navigare */}
                <nav className="nav-container">

                    <div className="nav-buttons">
                        <Link to="/login" className="nav-button">Login</Link>
                       <Link to="/register" className="nav-button">Register</Link>
                        { /* <Link to="/profile" className="nav-button">Profil</Link> */}
                    </div>
                </nav>

                {/* Conținutul paginii va fi randat mai jos */}
                <div style={{ padding: '20px' }}>
                    <Routes>
                        <Route path="/login" element={<Login />} />
                        <Route path="/register" element={<Register />} />
                        <Route path="/profile" element={<ProfilePage />} />
                    </Routes>
                </div>
            </div>
        </Router>
    );
};
//<Route path="/profile" element={<ProfilePage />} /> {/* Rută nouă */}

export default App;
